eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   getProjectBySlug: () => (/* binding */ getProjectBySlug),\n/* harmony export */   projectsData: () => (/* binding */ projectsData)\n/* harmony export */ });\nconst projectsData = [\n    {\n        slug: 'residenceia',\n        title: 'Residenceia - Smart Real Estate Property Buying & Selling Platform',\n        cardTitle: 'Residenceia - Smart Real Estate Platform',\n        cardDescription: 'Centralizing verified properties and AI-driven market insights for faster, confident real estate decisions.',\n        category: 'Real Estate',\n        tags: [\n            'Real Estate',\n            'PropTech'\n        ],\n        image: '/images/recidencia.jpeg',\n        accentColor: '#3B82F6',\n        accentColorRgb: '59, 130, 246',\n        styleColors: [\n            {\n                name: 'Primary Blue',\n                hex: '#3B82F6',\n                textColor: 'text-white'\n            },\n            {\n                name: 'Deep Dark',\n                hex: '#0A0A0A',\n                textColor: 'text-white'\n            },\n            {\n                name: 'Clean Neutral',\n                hex: '#F5F5F5',\n                textColor: 'text-black'\n            }\n        ],\n        metadata: [\n            {\n                label: 'Category',\n                value: 'Real Estate'\n            },\n            {\n                label: 'Services',\n                value: 'UI/UX Design'\n            },\n            {\n                label: 'Focus',\n                value: 'Web & Mobile'\n            },\n            {\n                label: 'Outcome',\n                value: 'AI-Driven Platform'\n            }\n        ],\n        description: `Residenceia was created to help property buyers and sellers streamline the real estate transaction process. Surveys of 150 property seekers and sellers revealed 68% struggled with fake or outdated listings, 75% found property valuation and pricing confusing, and 70% felt frustrated by the heavy reliance on costly middlemen. The platform centralizes verified properties, simplifies direct communication workflows, and highlights smart AI-driven market insights for faster, confident real estate decisions.`,\n        problemIntro: `Residenceia was built to tackle real frustrations in the property market. Users struggled with scattered listings across multiple unverified portals, opaque property pricing, and a severe lack of trust between buyers and sellers. Many could not make quick, confident financial decisions due to hidden details and complex negotiation processes. Highlighting the most accurate property data while keeping the buying and selling interface transparent and accessible was a key challenge.`,\n        problems: [\n            {\n                title: 'Fragmented Listings',\n                text: 'Property listings and seller details were scattered across multiple fragmented websites and local brokers, causing extreme confusion and delays.'\n            },\n            {\n                title: 'Fake Listings & Inaccurate Valuations',\n                text: 'Fake listings and highly inaccurate property valuations were often identified too late, leading to wasted time, lost trust, and financial uncertainty.'\n            },\n            {\n                title: 'Cluttered & Disconnected Platforms',\n                text: 'Platforms were cluttered with ads and lacked a centralized, secure way for buyers and sellers to connect directly, slowing down the transaction process.'\n            }\n        ],\n        solutionIntro: `To address scattered listings and a lack of transparency, we created a centralized, user-focused Residenceia platform. It organizes verified property listings, AI-driven price estimations, and buyer-seller communications in one secure place. The clean interface simplifies property discovery, reduces cognitive load, and allows both buyers and sellers to bypass unnecessary intermediaries and act confidently.`,\n        solutions: [\n            {\n                title: 'Centralized Verified Listings',\n                text: 'Centralize verified property listings, smart search filters, and transaction tracking into a single, easily navigable platform interface.'\n            },\n            {\n                title: 'AI-Powered Price Estimation',\n                text: 'AI-powered price estimation and automated listing verification ensured users could identify fair market values and avoid fake properties immediately.'\n            },\n            {\n                title: 'Direct Communication Tools',\n                text: 'Direct buyer-seller communication and secure scheduling tools were prioritized with clear visual indicators for faster, transparent deal-making.'\n            }\n        ],\n        styleGuide: `Designed with a modern, trust-inspiring aesthetic. The UI utilizes clean typography, ample whitespace to highlight high-quality property imagery, and intuitive card-based components for listings. Primary colors focus on reliable blues and clean neutrals to instill financial confidence, paired with consistent, accessible iconography for amenities and smart metrics.`,\n        workflow: `In a typical property search, users browse homes, compare market prices, and attempt to contact property owners. Previously, scattered data, fake photos, and unresponsive brokers caused endless delays and confusion. With Residenceia, information flows seamlessly: smart algorithms highlight highly relevant properties, the AI price estimator provides instant market clarity, and buyers can instantly schedule visits or chat directly with verified sellers without switching between multiple apps or making endless phone calls.`,\n        result: `Residenceia transformed how people buy and sell real estate by providing a centralized, transparent, and AI-enhanced platform. Users can quickly discover verified properties, evaluate fair market prices, and seamlessly oversee their booking progress. The user-focused interface reduces market friction and highlights critical insights, enabling faster, data-driven real estate decisions. It improves transaction efficiency by minimizing middleman dependency and giving users total confidence in their buying or selling journey.`,\n        nextSlug: 'fitsync',\n        nextTitle: 'Fitsync - All-in-One Fitness Tracking & Workout Companion'\n    },\n    {\n        slug: 'fitsync',\n        title: 'Fitsync - All-in-One Fitness Tracking & Workout Companion',\n        cardTitle: 'Fitsync - Fitness Tracking & Workout Companion',\n        cardDescription: 'Centralizing health data, workout logging, and nutrition tracking with real-time progress metrics.',\n        category: 'Health & Fitness',\n        tags: [\n            'Health & Fitness',\n            'Mobile App'\n        ],\n        image: '/images/fitsinc.jpeg',\n        accentColor: '#22C55E',\n        accentColorRgb: '34, 197, 94',\n        styleColors: [\n            {\n                name: 'Electric Green',\n                hex: '#22C55E',\n                textColor: 'text-white'\n            },\n            {\n                name: 'Deep Dark',\n                hex: '#111111',\n                textColor: 'text-white'\n            },\n            {\n                name: 'Energetic Orange',\n                hex: '#F97316',\n                textColor: 'text-white'\n            }\n        ],\n        metadata: [\n            {\n                label: 'Category',\n                value: 'Health & Fitness'\n            },\n            {\n                label: 'Services',\n                value: 'UI/UX Design'\n            },\n            {\n                label: 'Focus',\n                value: 'Mobile App'\n            },\n            {\n                label: 'Outcome',\n                value: 'Unified Fitness Hub'\n            }\n        ],\n        description: `FitSync was created to help fitness enthusiasts and beginners streamline their workout and nutrition management. Surveys of 48 active individuals revealed 68% struggled to track their progress consistently, 74% found managing separate diet and workout apps frustrating, and 65% lacked clear insights to adjust their routines. The app centralizes health data, simplifies workout logging, and highlights critical progress metrics for faster, confident fitness decisions.`,\n        problemIntro: `FitSync was built to tackle real workout frustrations. Users struggled with scattered diet and exercise data, unclear progress visibility, and cluttered fitness apps. Many could not stay consistent or understand why they weren't seeing results. Highlighting the most important daily targets while keeping the interface simple and motivating during a workout was a key challenge.`,\n        problems: [\n            {\n                title: 'Scattered Health Data',\n                text: 'Workout logs, nutrition tracking, and daily step counts were scattered across multiple tools and notebooks, making consistency difficult.'\n            },\n            {\n                title: 'Late-Detected Plateaus',\n                text: 'Fitness plateaus or missed nutritional targets were often identified too late to prevent loss of motivation effectively.'\n            },\n            {\n                title: 'Cluttered Dashboards',\n                text: 'Dashboards were cluttered with overly complex charts, failing to prioritize critical daily actions for quick, mid-workout decision-making.'\n            }\n        ],\n        solutionIntro: `To address scattered data and cluttered fitness apps, we created a centralized, user-focused FitSync dashboard. It organizes workout plans, nutrition, and recovery stats in one place, provides real-time progress alerts, and highlights critical insights. The clean interface simplifies logging, reduces cognitive load during exercises, and allows users to train confidently and efficiently.`,\n        solutions: [\n            {\n                title: 'Unified Fitness Dashboard',\n                text: 'Centralize workout routines, macro tracking, and body metrics into a single, easily navigable dashboard interface.'\n            },\n            {\n                title: 'Real-Time Progress Alerts',\n                text: 'Real-time set tracking and milestone alerts ensured users could identify their progress and adjust their intensity immediately.'\n            },\n            {\n                title: 'Visual Progress Indicators',\n                text: 'Key daily targets were prioritized with clear visual indicators like activity rings and progress bars for faster, informed routine adjustments.'\n            }\n        ],\n        styleGuide: `Designed with a high-energy, distraction-free aesthetic. The UI utilizes a deep dark mode to reduce eye strain in gym environments, paired with vibrant neon accents — like electric green and energetic orange — to highlight completed goals. Components feature large, accessible touch targets, ensuring sweaty or shaky hands can easily log reps and sets without frustration.`,\n        workflow: `In a typical day, users log their meals, track their gym reps, and monitor daily step goals. Previously, scattered data across different apps caused friction and abandoned tracking. With FitSync, information flows seamlessly: alerts highlight daily targets, dashboards show real-time workout metrics, and users can make quick, informed health decisions without switching between multiple tools or notebooks.`,\n        result: `FitSync transformed how individuals manage their fitness journeys by providing a centralized and real-time dashboard. Users can quickly track workout sets, monitor nutritional intake, and oversee weekly progress. The user-focused interface reduces friction and highlights critical health insights, enabling faster, data-driven routine adjustments. It improves workout consistency by minimizing logging effort, giving users confidence in their daily fitness habits.`,\n        nextSlug: 'dineflow',\n        nextTitle: 'DineFlow - Intuitive Food Ordering & Restaurant Discovery'\n    },\n    {\n        slug: 'dineflow',\n        title: 'DineFlow - Intuitive Food Ordering & Restaurant Discovery Solution',\n        cardTitle: 'DineFlow - Food Ordering & Restaurant Discovery',\n        cardDescription: 'Centralizing dining data, restaurant discovery, and real-time ordering for confident, frictionless dining.',\n        category: 'Food & Dining',\n        tags: [\n            'Food & Dining',\n            'Mobile App'\n        ],\n        image: '/images/dineflow.jpeg',\n        accentColor: '#F97316',\n        accentColorRgb: '249, 115, 22',\n        styleColors: [\n            {\n                name: 'Vibrant Orange',\n                hex: '#F97316',\n                textColor: 'text-white'\n            },\n            {\n                name: 'Deep Red',\n                hex: '#DC2626',\n                textColor: 'text-white'\n            },\n            {\n                name: 'Clean White',\n                hex: '#FAFAFA',\n                textColor: 'text-black'\n            }\n        ],\n        metadata: [\n            {\n                label: 'Category',\n                value: 'Food & Dining'\n            },\n            {\n                label: 'Services',\n                value: 'UI/UX Design'\n            },\n            {\n                label: 'Focus',\n                value: 'Mobile App'\n            },\n            {\n                label: 'Outcome',\n                value: 'Unified Dining Hub'\n            }\n        ],\n        description: `DineFlow was created to help food enthusiasts streamline restaurant discovery, table reservations, and digital food ordering. Surveys of 45 frequent diners revealed 67% struggled with fragmented apps for reviews and ordering, 71% found menu pricing and hidden fees confusing, and 63% lacked reliable real-time table availability. The app centralizes dining data, simplifies ordering workflows, and highlights accurate reviews and wait times for faster, confident dining choices.`,\n        problemIntro: `DineFlow was built to tackle real dining and ordering frustrations. Users struggled with scattered reviews and menus, unclear delivery or wait times, and cluttered food delivery apps. Many could not make quick, confident decisions on where or what to eat. Highlighting the most relevant dining options while keeping the interface appetizing and actionable was a key challenge.`,\n        problems: [\n            {\n                title: 'Fragmented Dining Platforms',\n                text: 'Restaurant reviews, digital menus, and table reservation tools were scattered across multiple platforms and apps, causing confusion.'\n            },\n            {\n                title: 'Late-Identified Delays',\n                text: 'Unavailable menu items or unexpectedly long wait times were often identified too late to prevent dining plan disruptions effectively.'\n            },\n            {\n                title: 'Cluttered Interfaces',\n                text: 'App interfaces were cluttered with irrelevant promotions, failing to prioritize personalized recommendations for fast decision-making.'\n            }\n        ],\n        solutionIntro: `To address scattered dining data and cluttered apps, we created a centralized, user-focused DineFlow app. It organizes restaurant discovery, food ordering, and table booking in one place, provides real-time status updates, and highlights verified reviews. The clean interface simplifies decision-making, reduces cognitive load, and allows users to order or dine out confidently and efficiently.`,\n        solutions: [\n            {\n                title: 'Centralized Dining Hub',\n                text: 'Centralize restaurant discovery, digital menus, and reservation data into a single, easily navigable app interface.'\n            },\n            {\n                title: 'Real-Time Order Tracking',\n                text: 'Real-time order tracking and live table availability ensured users could identify wait times and sold-out items immediately.'\n            },\n            {\n                title: 'Smart Dining Preferences',\n                text: 'Key dining preferences were prioritized with clear visual indicators like dietary tags, ratings, and pricing tiers for faster, informed food choices.'\n            }\n        ],\n        styleGuide: `Designed with an appetizing, warm, and highly visual aesthetic. The UI utilizes a warm color palette featuring vibrant orange and deep red accents to stimulate appetite, paired with expansive white space to let high-quality food photography stand out. Components feature soft, rounded edges and large, accessible CTAs to ensure the ordering and checkout process is entirely frictionless.`,\n        workflow: `In a typical day, users search for nearby restaurants, check menus for dietary options, and place orders or book tables. Previously, scattered data across different review and delivery apps caused delays, confusion, and frustration. With DineFlow, information flows seamlessly: live maps highlight nearby spots, menus show real-time item availability, and users can make quick, informed dining decisions without switching between multiple tools or browsing endless browser tabs.`,\n        result: `DineFlow transformed how people discover and order food by providing a centralized and real-time platform. Users can quickly track order statuses, monitor live wait times, and oversee group table bookings. The user-focused interface reduces decision fatigue and highlights culinary insights, enabling faster, craving-driven decisions. It improves the overall dining experience by minimizing friction, and giving users confidence in their daily meal plans.`,\n        nextSlug: 'renovaflow',\n        nextTitle: 'RenovaFlow - Smart Home Renovation Management Platform'\n    },\n    {\n        slug: 'renovaflow',\n        title: 'RenovaFlow - Smart Home Renovation Management Platform',\n        cardTitle: 'RenovaFlow - Home Renovation Management',\n        cardDescription: 'Centralizing contractor communications, budgets, and timelines for confident, efficient renovation management.',\n        category: 'Home Improvement',\n        tags: [\n            'Home Improvement',\n            'Dashboard'\n        ],\n        image: '/images/renova.jpeg',\n        accentColor: '#14B8A6',\n        accentColorRgb: '20, 184, 166',\n        styleColors: [\n            {\n                name: 'Bright Teal',\n                hex: '#14B8A6',\n                textColor: 'text-white'\n            },\n            {\n                name: 'Slate Gray',\n                hex: '#475569',\n                textColor: 'text-white'\n            },\n            {\n                name: 'Warm Neutral',\n                hex: '#F5F0EB',\n                textColor: 'text-black'\n            }\n        ],\n        metadata: [\n            {\n                label: 'Category',\n                value: 'Home Improvement'\n            },\n            {\n                label: 'Services',\n                value: 'UI/UX Design'\n            },\n            {\n                label: 'Focus',\n                value: 'Web Dashboard'\n            },\n            {\n                label: 'Outcome',\n                value: 'Unified Project Hub'\n            }\n        ],\n        description: `RenovaFlow was created to help homeowners and contractors streamline home remodeling and construction projects. Surveys of 42 homeowners and project managers revealed 68% struggled to track budgets in real time, 75% found contractor communication and invoices confusing, and 70% lacked clear insights into project timelines. The dashboard centralizes project data, simplifies workflows, and highlights critical milestones for faster, confident actions.`,\n        problemIntro: `RenovaFlow was built to tackle real renovation frustrations. Users struggled with scattered vendor quotes, unclear project progress, and cluttered communication channels. Many could not make quick, confident decisions regarding material approvals or budget overruns. Highlighting the most important timeline metrics while keeping the interface simple and actionable was a key challenge.`,\n        problems: [\n            {\n                title: 'Scattered Project Data',\n                text: 'Contractor communications, invoices, and material selections were scattered across multiple tools, emails, and spreadsheets, causing confusion.'\n            },\n            {\n                title: 'Late-Detected Overruns',\n                text: 'Budget overruns or material shipping delays were often identified too late to prevent costly project stalls effectively.'\n            },\n            {\n                title: 'Unreadable Timelines',\n                text: 'Project timelines were cluttered and hard to read, failing to prioritize critical approval metrics for fast decision-making.'\n            }\n        ],\n        solutionIntro: `To address scattered project data and cluttered timelines, we created a centralized, user-focused RenovaFlow dashboard. It organizes contractors, budgets, and materials in one place, provides real-time progress alerts, and highlights critical insights. The clean interface simplifies decision-making, reduces cognitive load, and allows homeowners and teams to act confidently and efficiently.`,\n        solutions: [\n            {\n                title: 'Centralized Project Dashboard',\n                text: 'Centralize contractor messages, budget tracking, and material choices into a single, easily navigable dashboard interface.'\n            },\n            {\n                title: 'Real-Time Budget Alerts',\n                text: 'Real-time project timeline tracking and budget alerts ensured users could identify critical delays or overspending immediately.'\n            },\n            {\n                title: 'Visual Milestone Indicators',\n                text: 'Key project milestones were prioritized with clear visual indicators for faster, informed approval decision-making.'\n            }\n        ],\n        styleGuide: `Designed with a structural, clean, and modern architectural aesthetic. The UI utilizes a trustworthy color palette of slate grays and warm wood tones to evoke interior design, paired with bright teal accents to highlight pending approvals and action items. Components feature structured grid layouts, visual progress bars, and easy-to-read financial summary cards.`,\n        workflow: `In a typical day, users check renovation timelines, track contractor updates, and monitor material budgets. Previously, scattered data caused delays, miscommunication, and confusion. With RenovaFlow, information flows seamlessly: alerts highlight critical material delays, dashboards show real-time budget metrics, and homeowners can make quick, informed approval decisions without switching between multiple email threads or spreadsheets.`,\n        result: `RenovaFlow transformed how homeowners and contractors manage renovations by providing a centralized and real-time dashboard. Users can quickly track timeline phases, monitor material costs, and oversee project progress. The user-focused interface reduces confusion and highlights critical budget insights, enabling faster, data-driven decisions. It improves operational efficiency by minimizing costly errors, and giving teams confidence in their daily workflows.`,\n        nextSlug: 'residenceia',\n        nextTitle: 'Residenceia - Smart Real Estate Property Buying & Selling Platform'\n    }\n];\nfunction getProjectBySlug(slug) {\n    return projectsData.find((p)=>p.slug === slug);\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/app/projects/projectsData.ts\n");

